{{CSS|content=@import url('https://fonts.googleapis.com/css2?family=Rubik:wght@300;500;700&family=Amatic+SC:wght@400;700&display=swap');

:root {
  --seuss-purple-dark: 50, 10, 70;
  --seuss-purple-light: 140, 90, 180;
  --seuss-teal: 80, 200, 180;
  --seuss-pink: 255, 100, 150;
  --seuss-gold: 255, 180, 50;
  --seuss-shadow: 0, 0, 0;

  --body-font: 'Rubik', sans-serif;
  --whimsy-font: 'Amatic SC', cursive;
  --mono-font: 'Fantasque Sans Mono', monospace;
}

.page-container .page {
  border: 3px double rgb(var(--seuss-pink));
  margin: 12px auto;
  border-radius: 25px;
  box-shadow: 0 0 15px rgba(var(--seuss-shadow), 0.6);
  background: linear-gradient(
    135deg,
    rgb(var(--seuss-purple-dark)),
    rgb(var(--seuss-purple-light)),
    rgba(var(--seuss-teal), 0.3)
  );
  padding: 1.5rem;
  animation: seuss-bounce 12s ease-in-out infinite;
  background-image:
    linear-gradient(rgba(var(--seuss-purple-dark), 0.2), rgba(var(--seuss-purple-dark), 0.2)),
    repeating-linear-gradient(45deg, rgba(var(--seuss-shadow), 0.1) 0px, rgba(var(--seuss-shadow), 0.1) 10px, transparent 10px, transparent 20px);
}

.theme-fandomdesktop-dark {
  --theme-page-background-color: rgb(var(--seuss-purple-dark));
  --theme-page-background-color--secondary: rgba(var(--seuss-purple-light), 0.8);
  --theme-link-color: rgb(var(--seuss-gold));
  --theme-border-color: rgb(var(--seuss-pink));
  --theme-community-header-color: rgb(var(--seuss-teal));
  --theme-sticky-nav-background-color: rgba(var(--seuss-purple-dark), 0.95);
  --theme-sticky-nav-text-color: rgb(var(--seuss-gold));
  --theme-sticky-nav-text-color--hover: rgb(var(--seuss-pink));
}

.theme-fandomdesktop-light {
  --theme-page-background-color: rgba(var(--seuss-purple-light), 0.9);
  --theme-page-background-color--secondary: rgb(var(--seuss-purple-dark));
  --theme-link-color: rgb(var(--seuss-teal));
  --theme-border-color: rgb(var(--seuss-gold));
  --theme-community-header-color: rgb(var(--seuss-pink));
  --theme-sticky-nav-background-color: rgba(var(--seuss-purple-light), 0.95);
  --theme-sticky-nav-text-color: rgb(var(--seuss-purple-dark));
  --theme-sticky-nav-text-color--hover: rgb(var(--seuss-teal));
}

.page-side-tools .page-side-tool {
  border: 3px dashed rgb(var(--seuss-teal));
  box-shadow: 0 0 8px rgba(var(--seuss-shadow), 0.4);
  border-radius: 15px;
  background-color: rgba(var(--seuss-purple-dark), 0.85);
  transform: skewY(-2deg);
  transition: transform 0.3s ease;
}
.page-side-tool:hover {
  transform: skewY(2deg);
}

.titleblock, .dark-titleblock {
  background: radial-gradient(circle at top, rgba(var(--seuss-purple-light), 0.9), rgb(var(--seuss-purple-dark)));
  border: 4px solid rgb(var(--seuss-gold));
  border-radius: 30px;
  padding: 1rem;
  font-family: var(--whimsy-font);
  font-weight: 700;
  color: rgb(var(--seuss-pink));
  text-shadow: 2px 2px 4px rgba(var(--seuss-shadow), 0.7);
  font-size: 2.5em;
  transform: rotate(-1deg);
}

.progress {
  background: rgba(var(--seuss-purple-dark), 0.9);
  border: 3px double rgb(var(--seuss-teal));
  border-radius: 20px;
  color: rgb(var(--seuss-pink));
  box-shadow: 0 0 10px rgba(var(--seuss-shadow), 0.5);
}
.progress .bar {
  background: linear-gradient(to right, rgb(var(--seuss-teal)), rgb(var(--seuss-gold)));
  border-radius: 15px;
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--whimsy-font);
  color: rgb(var(--seuss-gold));
  text-transform: uppercase;
  letter-spacing: 3px;
  text-shadow: 3px 3px 5px rgba(var(--seuss-shadow), 0.8);
  font-size: calc(1.5rem + 0.5vw);
  transform: rotate(-2deg);
  animation: seuss-wiggle 8s ease-in-out infinite;
}
h1 {
  font-size: calc(2rem + 1vw);
}

@keyframes seuss-bounce {
  0%, 100% {
    transform: translateY(0) rotate(-1deg);
  }
  50% {
    transform: translateY(-8px) rotate(1deg);
  }
}

@keyframes seuss-wiggle {
  0%, 100% {
    transform: rotate(-2deg);
  }
  50% {
    transform: rotate(2deg);
  }
}
}}


